+
+        buf.set(0, 0, Cell::from_char('Y'));
+        tt.record(&buf, FrameMetadata::new(1, Duration::from_millis(1)));
+
+        buf.set(0, 0, Cell::from_char('Z'));
+        tt.record(&buf, FrameMetadata::new(2, Duration::from_millis(1)));
+
